&lt;p style=&quot;&quot;&gt;x&lt;span style=&quot; line-height: 0; position: relative; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;3&lt;/span&gt;&amp;nbsp;+ y&lt;span style=&quot; line-height: 0; position: relative; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;3&lt;/span&gt;&amp;nbsp;+ z&lt;span style=&quot; line-height: 0; position: relative; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;3&lt;/span&gt;&amp;nbsp;- 3xyz = (x + y + z)[(x + y + z)&lt;span style=&quot; line-height: 0; position: relative; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;2&lt;/span&gt;&amp;nbsp;- 3(xy + yz + zx)]&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;गणना:&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;मानों को सूत्र में रखने पर हमें प्राप्त होता है&lt;/p&gt;

&lt;p style=&quot;&quot;&gt;&lt;span style=&quot;&quot;&gt;a&lt;/span&gt;&lt;span style=&quot; line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;3&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;+ b&lt;/span&gt;&lt;span style=&quot; line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;3&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;+ c&lt;/span&gt;&lt;span style=&quot; line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;3&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;- 3abc = 8&amp;nbsp;&amp;times; (8&lt;/span&gt;&lt;span style=&quot; line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;2&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;- 3 &amp;times; 14)&lt;/span&gt;&lt;/p&gt;

